const items = $input.all();
const results = {};

for (const item of items) {
  const d = item.json;
  if (d.result?.username) {
    results.bot = {
      id: d.result.id,
      username: d.result.username,
      name: d.result.first_name,
      can_join_groups: d.result.can_join_groups
    };
  } else if ('url' in (d.result || {})) {
    results.webhook = {
      url: d.result.url || '(not set)',
      pending_updates: d.result.pending_update_count,
      allowed_updates: d.result.allowed_updates
    };
  } else if (Array.isArray(d.result)) {
    results.commands = d.result.map(c => `/${c.command} — ${c.description}`);
  }
}

const lines = [
  '=== @MEXAHI3MBOT Health Check ===',
  '',
  '🤖 Bot:',
  `  ID: ${results.bot?.id}`,
  `  Username: @${results.bot?.username}`,
  `  Name: ${results.bot?.name}`,
  '',
  '🔗 Webhook:',
  `  URL: ${results.webhook?.url}`,
  `  Pending updates: ${results.webhook?.pending_updates}`,
  `  Allowed: ${(results.webhook?.allowed_updates || []).join(', ')}`,
  '',
  '📋 Commands:',
  ...(results.commands?.map(c => `  ${c}`) || ['  (none)']),
];

return [{ json: { report: lines.join('\n'), raw: results } }];
